<template><view class="page"><xy-header title="订单详情"/><view v-if="order" class="wrap"><view class="card"><text class="status">{{labels[order.status]||order.status}}</text><text class="no">订单号：{{order.orderNo}}</text><text v-if="order.receiverSnapshot" class="address">{{order.receiverSnapshot}}</text></view><view class="card" v-for="item in order.items" :key="item.productId"><view class="goods"><image v-if="item.coverUrl" :src="item.coverUrl" mode="aspectFill"/><view><text>{{item.productName}}</text><text>¥{{item.salePrice}} × {{item.quantity}}</text></view></view></view><view class="card"><view>商品金额 <text>¥{{order.totalAmount}}</text></view><view>运费 <text>¥{{order.freightAmount}}</text></view><view class="pay">应付 ¥{{order.payableAmount}}</view></view><button v-if="order.status==='PENDING_PAYMENT'" class="submit" @click="pay">微信支付</button><button v-if="order.status==='PENDING_PAYMENT'" class="line" @click="cancelOrder">取消订单</button><button v-if="order.status==='SHIPPED'" class="submit" @click="receipt">确认收货</button><button v-if="['PAID','SHIPPED','COMPLETED'].includes(order.status)" class="line" @click="aftersale">申请售后</button></view><view v-else class="empty">订单不存在</view></view></template>
<script>
import{appRequest,ensureMemberSession,showRequestError}from '../../utils/api'
export default{data(){return{order:null,orderNo:'',labels:{PENDING_PAYMENT:'待支付',PAID:'待发货',SHIPPED:'待收货',COMPLETED:'已完成',CANCELED:'已取消',AFTER_SALE:'售后中',REFUNDED:'已退款'}}},onLoad(q){this.orderNo=q.orderNo;this.load()},methods:{async load(){try{await ensureMemberSession();this.order=await appRequest({url:`/app/orders/${this.orderNo}`})}catch(e){showRequestError(e)}},async pay(){try{const p=await appRequest({url:`/app/orders/${this.orderNo}/payment`,method:'POST'});uni.requestPayment({...p,success:()=>this.load(),fail:()=>uni.showToast({title:'支付未完成',icon:'none'})})}catch(e){showRequestError(e)}},async cancelOrder(){try{await appRequest({url:`/app/orders/${this.orderNo}/cancel`,method:'POST'});this.load()}catch(e){showRequestError(e)}},async receipt(){try{await appRequest({url:`/app/orders/${this.orderNo}/receipt`,method:'POST'});this.load()}catch(e){showRequestError(e)}},aftersale(){uni.navigateTo({url:`/pages/order/aftersale?orderNo=${this.orderNo}`})}}}
</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{margin-bottom:20rpx;padding:28rpx;border-radius:22rpx;background:#fff}.status{display:block;color:var(--xy-primary);font-size:34rpx;font-weight:700}.no,.address{display:block;margin-top:14rpx;color:var(--xy-ink-3);font-size:24rpx}.goods{display:flex;gap:20rpx;align-items:center}.goods image{width:120rpx;height:120rpx;border-radius:16rpx;background:var(--xy-mint)}.goods text{display:block;margin:10rpx}.card>view{display:flex;justify-content:space-between;margin:16rpx 0}.pay{font-weight:700;color:var(--xy-danger)}.submit,.line{margin:18rpx 24rpx;width:auto}.submit{background:var(--xy-primary);color:#fff}.empty{padding:160rpx;text-align:center;color:var(--xy-muted)}</style>
